import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Divider } from '@mui/material';
import response from './response.json';

interface TipCalculatorData {
  billAmount: number;
  tipPercentage: number;
  tipAmount: number;
  totalAmount: number;
  splitBy: number;
  perPerson: number;
}

interface MetaData {
  theme: string;
  dataMode: string;
  layout: string;
  primaryColor: string;
  accentColor: string;
  chartTypes: string[];
}

export default function Widget() {
  const tipData = response.data as TipCalculatorData;
  const metaData = response.meta as MetaData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 400, bgcolor: metaData.theme === 'light' ? '#FFFFFF' : '#333333' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: metaData.primaryColor }}>
              Quick Tip Calculator
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Bill Amount: ${tipData.billAmount.toFixed(2)}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Tip Percentage: {tipData.tipPercentage}%
            </Typography>
          </Box>

          <Divider sx={{ my: 1 }} />

          <Box>
            <Typography variant="body2" color="text.secondary">
              Tip Amount: ${tipData.tipAmount.toFixed(2)}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Total Amount: ${tipData.totalAmount.toFixed(2)}
            </Typography>
          </Box>

          <Divider sx={{ my: 1 }} />

          <Box>
            <Typography variant="body2" color="text.secondary">
              Split Among: {tipData.splitBy} people
            </Typography>
            <Typography variant="body2" sx={{ color: metaData.accentColor, fontWeight: 500 }}>
              Per Person: ${tipData.perPerson.toFixed(2)}
            </Typography>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
